-- Migration: séquestre 2025 historical data from Hospitable PDFs
CREATE TABLE IF NOT EXISTS sequestre_rapport_item (
  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  agence text NOT NULL DEFAULT 'dcb',
  annee integer NOT NULL,
  mois text NOT NULL,
  bien_id uuid, -- pas de FK: données historiques, certains biens peuvent ne plus exister
  code_db text,
  bien_name text NOT NULL,
  owner_name text,
  facture_chaos boolean DEFAULT false,
  source text,
  vir_statut text,
  vir_montant numeric(12,2),
  vir_note text,
  hon_ht numeric(12,2),
  hon_ttc numeric(12,2),
  menages numeric(12,2),
  debours numeric(12,2),
  taxe_sejour numeric(12,2),
  com_distrib numeric(12,2),
  created_at timestamptz DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_seq_rapport_agence_annee ON sequestre_rapport_item(agence, annee);
CREATE INDEX IF NOT EXISTS idx_seq_rapport_mois ON sequestre_rapport_item(mois);

-- RLS
ALTER TABLE sequestre_rapport_item ENABLE ROW LEVEL SECURITY;
CREATE POLICY "seq_rapport_read" ON sequestre_rapport_item FOR SELECT USING (true);
CREATE POLICY "seq_rapport_write" ON sequestre_rapport_item FOR ALL USING (true);

-- Data 2025
